// ===========================================================================
// RF Inference Functions
// ===========================================================================

#define RF_READ_NODE(idx) ({ \
    rf_node_t _n; \
    memcpy_P(&_n, &RF_NODES[idx], sizeof(rf_node_t)); \
    _n; })

static inline uint8_t rf_predict_tree(uint32_t treeIdx, const float* features) {
    uint32_t nodeIdx = pgm_read_dword(&RF_TREE_ROOTS[treeIdx]);
    rf_node_t node = RF_READ_NODE(nodeIdx);
    
    while (node.featureIndex >= 0) {
        if (features[node.featureIndex] < node.threshold) {
            nodeIdx = node.leftChild;
        } else {
            nodeIdx = node.rightChild;
        }
        node = RF_READ_NODE(nodeIdx);
    }
    return node.label;
}

static inline uint8_t rf_predict(const float* features) {
    uint16_t votes[5] = {0};
    for (uint32_t t = 0; t < RF_NUM_TREES; t++) {
        uint8_t pred = rf_predict_tree(t, features);
        if (pred < 5) votes[pred]++;
    }

    uint8_t best = 0;
    uint16_t maxVotes = 0;
    for (uint8_t i = 0; i < 5; i++) {
        if (votes[i] > maxVotes) {
            maxVotes = votes[i];
            best = i;
        }
    }
    return best;
}

static inline uint8_t rf_predict_with_confidence(const float* features, float* confidence) {
    uint16_t votes[5] = {0};
    for (uint32_t t = 0; t < RF_NUM_TREES; t++) {
        uint8_t pred = rf_predict_tree(t, features);
        if (pred < 5) votes[pred]++;
    }

    uint8_t best = 0;
    uint16_t maxVotes = 0;
    for (uint8_t i = 0; i < 5; i++) {
        if (votes[i] > maxVotes) {
            maxVotes = votes[i];
            best = i;
        }
    }

    *confidence = (float)maxVotes / (float)RF_NUM_TREES;
    return best;
}

static inline const char* rf_get_class_name(uint8_t idx) {
    return (idx < 5) ? RF_CLASS_NAMES[idx] : "unknown";
}

